final:
module Reg_32_async_load(
   input                clk,
   input                rst,
   input                load,
   input  [31:0]        load_val,
   output reg [31:0]    Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt)begin
        if(rst) Q <= 32'd0;
        else if(load) Q <= load_val;
    end
endmodule
